import threading
import queue
from deep_translator import GoogleTranslator # type: ignore

class FrenchTranslator(threading.Thread):
    def __init__(self, id, queue, packerQueue):
        super().__init__(daemon=True)
        self.queue = queue
        self.id = id
        self.packerQueue = packerQueue
        self.start()

    def run(self):
        while True:
            try:
                job = self.queue.get(timeout=10)
            except queue.Empty:
                continue

            translatedMsg = GoogleTranslator(source="auto", target="french").translate(job["value"]["data"])
            self.packerQueue.put({
                "uid": job["uid"],
                "value": {
                    "language": "french",
                    "original": job["value"]["data"],
                    "translated": translatedMsg
                }
            })

import threading
import queue
from TransactionDB import TransactionDB

class PackerThread(threading.Thread):
    def __init__(self, queue):
        super().__init__(daemon=True)
        self.queue = queue
        self.items = {}
        self.start()

    def run(self):
        self.db = TransactionDB()
        while True:
            try:
                translatedJobPart = self.queue.get(timeout=10)
            except queue.Empty:
                continue

            self.db.addTranslation(translatedJobPart)

            if self.db.isDone(translatedJobPart["uid"]):
                self.db.setDone(translatedJobPart["uid"])

